UPDATE TBL_USER_MST
   SET PASS_WD  = CONVERT(VARBINARY(500), CONVERT(VARCHAR(500), #{encUserPwd})),
       PASS_CDT = CONVERT(date, GETDATE()),
       UPD_DTTM = GETDATE(),
       UPD_USER = #{userId}
 WHERE COMP_CD = #{compCd}
   AND LTRIM(RTRIM(USER_ID)) = #{userId}
   AND ACTION_YN = 'Y'

UPDATE TBL_COMP_MST
   SET ACTION_YN = 'N', UPD_DTTM = GETDATE(), UPD_USER = #{updUser}, UPD_IP = #{updIp}
 WHERE COMP_CD = #{compCd} AND ACTION_YN = 'Y'

UPDATE TBL_COMPCONT_MST
   SET ACTION_YN = 'N', UPD_DTTM = GETDATE(), UPD_USER = #{updUser}, UPD_IP = #{updIp}
 WHERE COMP_CD = #{compCd} AND START_DT = #{startDt} AND END_DT = #{endDt} AND ACTION_YN = 'Y'

