SELECT CODE_CD AS codeCd, SUB_CODE AS subCode, SUB_CODE_NM AS subCodeNm
  FROM TBL_CODE_DTL
 WHERE ACTION_YN = 'Y'

  AND CODE_GB IN #{g}


  AND CODE_CD IN #{c}

 ORDER BY CODE_CD, SUB_CODE

